import{_ as t,o as r,c as i,a3 as o}from"./chunks/framework.CjquFG0V.js";const p=JSON.parse('{"title":"51. Higher Duties","description":"","frontmatter":{"title":"51. Higher Duties","eba":"Doctors in Training 2022-2026","topics":["hours","rosters","wages","higher-duties"]},"headers":[],"relativePath":"ebas/doctors-in-training/allowances/51-higher-duties.md","filePath":"ebas/doctors-in-training/allowances/51-higher-duties.md"}'),s={name:"ebas/doctors-in-training/allowances/51-higher-duties.md"};function a(n,e,c,l,d,h){return r(),i("div",null,[...e[0]||(e[0]=[o('<h1 id="_51-higher-duties" tabindex="-1">51. Higher Duties <a class="header-anchor" href="#_51-higher-duties" aria-label="Permalink to &quot;51. Higher Duties&quot;">​</a></h1><p><strong>51.1</strong> A Doctor is deemed to perform Higher Duties where a Doctor is required to perform the full duties in a designated Registrar role for a minimum period equivalent to the lesser of:</p><p><strong>(a)</strong> a period of more than five (5) consecutive working days; or</p><p><strong>(b)</strong> a week as prescribed in the Doctor&#39;s roster.</p><p><strong>51.2</strong> Where a Doctor performs Higher Duties, the Doctor will:</p><p><strong>(a)</strong> not be paid less than the minimum rate applicable to that higher classification for all time worked in excess of the period prescribed in 51.1(a) or (b), whichever is the lesser;</p><p><strong>(b)</strong> where the Doctor is performing Higher Duties as a Registrar, be entitled to all conditions and benefits of a Registrar for all time worked in excess of the period prescribed in 51.1(a) or (b), whichever is the lesser; and</p><p><strong>(c)</strong> not experience a financial detriment as a result of performing Higher Duties</p><p><strong>51.3</strong> When calculating the period of consecutive working days prescribed in subclause 51.1(a), rostered days off do not contribute to the calculation, and do not break the period of consecutive shifts.</p><p><strong>51.4</strong> Subject to subclause 51.2(c), where a HMO/MO works in a designated Registrar role for a period less than outlined in clause 51.1, they will be entitled to be paid at the minimum rate of a first year Registrar, but will not be entitled to any further benefits or allowances of a Registrar.</p><p>Plain language terms: acting up, HDA.</p>',11)])])}const u=t(s,[["render",a]]);export{p as __pageData,u as default};
